         this string? input,
         int length,
         string truncationString = "…",
         ITruncator? truncator = null,
         TruncateFrom truncateFrom = TruncateFrom.Right)
     {
         if (input == null)
         {
             return null;
         }

         truncator ??= DefaultTruncator;
         return truncator.Truncate(input, length, truncationString, truncateFrom);
     }
